export const newPackAlpha = {
  id: 'new-pack-alpha',
  name: 'New Pack Alpha',
  bpm: SPINE_BPM,
  description: 'New Pack Alpha — generated by Pack Builder Agent.',
  pads: newPackAlphaPads,
  audioUrls: buildAudioUrls(B),
}

function buildAudioUrls(base: string): Record<string, string> {
  const paths = new Set<string>()
  for (const pad of newPackAlphaPads) paths.add(pad.audioFile)
  return Object.fromEntries([...paths].map((p) => [`${base}/${p}`, `${base}/${p}`]))
}

export function buildNewPackAlphaCompatiblePack(): CompatibleAudioPack {
  const pads: CompatiblePackPad[] = newPackAlphaPads.map((p) => ({
    id: p.id,
    label: p.label,
    audioFile: p.audioFile,
    sourceFile: p.sourceFile,
    gameCategory: (p.category === 'voice' ? 'voice' : p.category) as CompatiblePackPad['gameCategory'],
    volume: p.volume,
    notes: p.notes,
    compatibility: {
      bpm: p.bpm,
      key: p.key,
      bars: p.bars,
      energy: p.energy,
      category: p.category as CompatiblePackPad['compatibility']['category'],
      harmonicGroup: p.harmonicGroup as CompatiblePackPad['compatibility']['harmonicGroup'],
      transientDensity: p.transientDensity,
      lowEndWeight: p.lowEndWeight,
      mixabilityScore: p.mixabilityScore,
      playbackQuantization: (p.playbackQuantization ?? (p.playbackMode === 'one-shot' ? 'immediate' : 'bar')) as QuantizeMode,
      oneShot: p.playbackMode === 'one-shot',
    },
  }))
  return {
    id: newPackAlpha.id,
    name: newPackAlpha.name,
    description: newPackAlpha.description,
    philosophy: 'new-pack-alpha',
    spine: { bpm: SPINE_BPM, key: SPINE_KEY, bars: SPINE_BARS, harmonicTonic: 'tonic' },
    pads,
    audioBasePath: B,
    audioUrls: newPackAlpha.audioUrls,
  }
}

export const newPackAlphaCompatible = buildNewPackAlphaCompatiblePack()
